/*
==================================================
  Design System Tokens
==================================================
*/
:root {
    /* Colors */
    --color-primary-teal: #00C0C0;
    --color-primary-black: #000000;
    --color-secondary-purple: #A88AEF;
    --color-secondary-white: #FFFFFF;
    --color-neutral-black: #000000;
    --color-neutral-white: #FFFFFF;
    --color-neutral-gray: #CCCCCC;
    --color-success: #0FAF70;
    --color-error: #CC3333;
    --color-warning: #FFB347;
    --color-info: #00A0C0;

    /* Typography */
    --font-heading: 'Cinzel Decorative', Georgia, serif;
    --font-body: 'Lora', 'Times New Roman', serif;
    --font-code: 'Source Code Pro', monospace;

    --font-size-h1: 36px;
    --font-size-h2: 28px;
    --font-size-h3: 22px;
    --font-size-body: 14px;
    --font-size-small: 12px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout */
    --sidebar-width: 210px;
    --max-page-width: 1180px;
}

/*
==================================================
  Global Reset & Base Styles
==================================================
*/
*,
*::before,
*::after {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    min-height: 100vh;
    background-color: var(--color-primary-black);
    color: var(--color-neutral-white);
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
}

a:hover,
a:focus {
    text-decoration: underline;
}

.page-container {
    max-width: var(--max-page-width);
    margin: 0 auto;
    padding: var(--space-3) var(--space-2) var(--space-6);
}

/*
==================================================
  Header / Nameplate
==================================================
*/
.site-header {
    text-align: center;
    margin-bottom: var(--space-3);
}

.header-inner {
    display: inline-block;
}

.header-ornament {
    height: 18px;
    margin-bottom: var(--space-1);
    position: relative;
}

.header-ornament::before,
.header-ornament::after {
    content: '✶✶✶';
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    color: var(--color-primary-teal);
    font-size: 14px;
    letter-spacing: 4px;
}

.header-ornament::after {
    top: 8px;
    opacity: 0.7;
}

.header-nameplate {
    text-align: center;
}

.nameplate-frame {
    display: inline-block;
    padding: 6px 64px;
    border: 2px solid var(--color-primary-teal);
    border-radius: 2px;
    position: relative;
    background-color: transparent;
}

.nameplate-frame::before,
.nameplate-frame::after {
    content: '';
    position: absolute;
    top: -6px;
    bottom: -6px;
    width: 18px;
    border-top: 2px solid var(--color-primary-teal);
    border-bottom: 2px solid var(--color-primary-teal);
}

.nameplate-frame::before {
    left: -18px;
}

.nameplate-frame::after {
    right: -18px;
}

.site-title {
    margin: 0;
    font-family: var(--font-heading);
    font-size: var(--font-size-h1);
    font-weight: var(--font-weight-regular);
    letter-spacing: 1px;
    color: var(--color-primary-teal);
    line-height: var(--line-height-tight);
}

/*
==================================================
  Layout: Sidebar + Main Content
==================================================
*/
.page-layout {
    display: flex;
    align-items: flex-start;
}

.sidebar-nav {
    flex: 0 0 var(--sidebar-width);
    padding-top: var(--space-3);
    padding-right: var(--space-2);
    font-size: var(--font-size-body);
}

.sidebar-top-ornament {
    height: 24px;
    margin-bottom: var(--space-1);
    position: relative;
}

.sidebar-top-ornament::before {
    content: '❧❧❧';
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    color: var(--color-primary-teal);
    font-size: 18px;
}

.sidebar-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.nav-item {
    position: relative;
    padding: var(--space-0-5) 0;
}

.nav-item + .nav-item {
    margin-top: 2px;
}

.nav-item::after {
    content: '❦';
    display: block;
    text-align: center;
    margin-top: 2px;
    color: var(--color-primary-teal);
    font-size: 11px;
}

.nav-item:last-child::after {
    content: '';
}

.sidebar-nav a {
    display: block;
    padding: 2px var(--space-1);
    color: var(--color-primary-teal);
    text-decoration: none;
    font-family: var(--font-body);
}

.sidebar-nav a:hover,
.sidebar-nav a:focus {
    color: var(--color-secondary-white);
    text-decoration: underline;
}

.main-content {
    flex: 1 1 auto;
    padding: var(--space-3) var(--space-3);
    min-height: 320px;
}

/*
==================================================
  Generic Card / Photo Frame & Gallery Controls
  (For reuse in page-specific content)
==================================================
*/
.photo-frame {
    display: inline-block;
    padding: 4px;
    border: 2px solid var(--color-neutral-white);
    box-shadow: 0 0 0 2px var(--color-secondary-purple);
    background-color: var(--color-neutral-black);
}

.photo-frame img {
    display: block;
}

.gallery-controls {
    margin-bottom: var(--space-2);
}

.gallery-controls .gallery-btn {
    display: inline-block;
    width: 32px;
    height: 32px;
    margin-right: var(--space-1);
    border: 1px solid var(--color-neutral-white);
    background-color: var(--color-primary-black);
    color: var(--color-neutral-white);
    text-align: center;
    line-height: 30px;
    font-size: 18px;
    text-decoration: none;
}

.gallery-controls .gallery-btn:hover,
.gallery-controls .gallery-btn:focus {
    border-color: var(--color-primary-teal);
    color: var(--color-primary-teal);
}

/*
==================================================
  Footer
==================================================
*/
.site-footer {
    margin-top: var(--space-5);
    padding-top: var(--space-3);
    font-size: var(--font-size-small);
    color: var(--color-neutral-gray);
}

.footer-inner {
    border-top: 1px solid #222222;
    padding-top: var(--space-2);
}

.footer-divider {
    height: 10px;
    margin-bottom: var(--space-1);
    position: relative;
}

.footer-divider::before {
    content: '✶ ✶ ✶';
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    color: var(--color-primary-teal);
    font-size: 11px;
    letter-spacing: 6px;
}

.footer-nav-list {
    list-style: none;
    margin: 0 0 var(--space-1);
    padding: 0;
    text-align: center;
}

.footer-item {
    display: inline-block;
    margin: 2px 10px;
    position: relative;
}

.footer-item::before {
    content: '•';
    position: absolute;
    left: -10px;
    color: var(--color-primary-teal);
}

.footer-item:first-child::before {
    content: '';
}

.footer-nav a {
    color: var(--color-primary-teal);
    text-decoration: none;
    white-space: nowrap;
}

.footer-nav a:hover,
.footer-nav a:focus {
    color: var(--color-secondary-white);
    text-decoration: underline;
}

.footer-copy {
    text-align: center;
    margin: 0;
}

.footer-year {
    color: var(--color-secondary-purple);
}

/*
==================================================
  Utility Classes
==================================================
*/
.text-center { text-align: center; }
.text-right { text-align: right; }

.hidden { display: none !important; }
